return {
  result: "I apologize; it seems we are having an issue."
};

// Get current year from system date
const currentYear = new Date().getFullYear();

for (const item of $input.all()) {
  const appointmentDate = item.json.body?.args?.appointment_date;

  if (appointmentDate) {
    const oldDate = new Date(appointmentDate);
    oldDate.setFullYear(currentYear);

    // Set the updated date back in the same nested structure
    item.json.body.args.appointment_date = oldDate.toISOString();
  }
}

return $input.all();
